// Aggregate RevOps events from HTTP Request response
const data = $input.all()[0].json;
const events = data.items || [];
return [{ json: { events, count: events.length } }];

// Aggregate Iceberg events from HTTP Request response
const data = $input.all()[0].json;
const events = data.items || [];
return [{ json: { events, count: events.length } }];

// Compute sync diff and output individual HTTP action items
const SYNC_TAG = 'n8n-calendar-sync-iceberg';
const PREFIX = '[Iceberg]';
const CLIENT_CAL = 'jort%40icebergops.com';
const REVOPS_CAL = 'joe%40revopsinflection.com';
const REVOPS_EMAIL = 'joe@revopsinflection.com';
const CLIENT_EMAIL = 'jort@icebergops.com';

const revopsData = $('Aggregate RevOps').first().json;
const clientData = $('Aggregate Iceberg').first().json;
const revopsEvents = revopsData.events || [];
const clientEvents = clientData.events || [];

// Only treat events tagged with OWN sync tag as synced.
// Events tagged with the other workflow's tag (n8n-calendar-sync) appear in
// revopsReal and are naturally relayed to the client calendar — no separate relay needed.
function isOurSyncedEvent(event) {
  return event.extendedProperties?.private?.syncSource === SYNC_TAG;
}
function getSyncSourceId(event) {
  return event.extendedProperties?.private?.syncSourceId || null;
}
function getAttendeeEmails(event) {
  return (event.attendees || []).map(a => (a.email || '').toLowerCase());
}

const revopsReal = revopsEvents.filter(e => !isOurSyncedEvent(e));
const revopsSynced = revopsEvents.filter(e => isOurSyncedEvent(e));
const clientReal = clientEvents.filter(e => !isOurSyncedEvent(e));
const clientSynced = clientEvents.filter(e => isOurSyncedEvent(e));

const actions = [];

// === RevOps (+ Blackthorn relay via revopsReal) -> Iceberg (busy blocks) ===
const clientSyncedMap = new Map();
for (const e of clientSynced) {
  const srcId = getSyncSourceId(e);
  if (!srcId) continue;
  if (clientSyncedMap.has(srcId)) {
    const prev = clientSyncedMap.get(srcId);
    const keepNew = new Date(e.updated || e.created || 0) >= new Date(prev.updated || prev.created || 0);
    const toDelete = keepNew ? prev : e;
    if (keepNew) clientSyncedMap.set(srcId, e);
    actions.push({
      direction: 'to-client', method: 'DELETE',
      url: 'https://www.googleapis.com/calendar/v3/calendars/' + CLIENT_CAL + '/events/' + toDelete.id + '?sendUpdates=none',
      body: '{}'
    });
  } else {
    clientSyncedMap.set(srcId, e);
  }
}

for (const event of revopsReal) {
  if (!event.start?.dateTime) continue;
  if (event.status === 'cancelled') continue;
  const attendees = getAttendeeEmails(event);
  if (attendees.includes(CLIENT_EMAIL)) { clientSyncedMap.delete(event.id); continue; }
  const existing = clientSyncedMap.get(event.id);
  if (existing) {
    if (existing.start?.dateTime !== event.start?.dateTime || existing.end?.dateTime !== event.end?.dateTime) {
      actions.push({
        direction: 'to-client',
        method: 'PATCH',
        url: 'https://www.googleapis.com/calendar/v3/calendars/' + CLIENT_CAL + '/events/' + existing.id + '?sendUpdates=none',
        body: JSON.stringify({
          start: { dateTime: event.start.dateTime, timeZone: event.start.timeZone || 'America/New_York' },
          end: { dateTime: event.end.dateTime, timeZone: event.end.timeZone || 'America/New_York' },
          reminders: { useDefault: false, overrides: [] }
        })
      });
    }
    clientSyncedMap.delete(event.id);
  } else {
    actions.push({
      direction: 'to-client',
      method: 'POST',
      url: 'https://www.googleapis.com/calendar/v3/calendars/' + CLIENT_CAL + '/events?sendUpdates=none',
      body: JSON.stringify({
        summary: '[Blocked] Busy',
        start: { dateTime: event.start.dateTime, timeZone: event.start.timeZone || 'America/New_York' },
        end: { dateTime: event.end.dateTime, timeZone: event.end.timeZone || 'America/New_York' },
        transparency: 'opaque',
        visibility: 'private',
        reminders: { useDefault: false, overrides: [] },
        extendedProperties: { private: { syncSource: SYNC_TAG, syncSourceId: event.id } }
      })
    });
  }
}
for (const [srcId, syncedEvent] of clientSyncedMap) {
  actions.push({
    direction: 'to-client',
    method: 'DELETE',
    url: 'https://www.googleapis.com/calendar/v3/calendars/' + CLIENT_CAL + '/events/' + syncedEvent.id + '?sendUpdates=none',
    body: '{}'
  });
}

// === Iceberg -> RevOps (full copy with prefix) ===
const revopsSyncedMap = new Map();
for (const e of revopsSynced) {
  const srcId = getSyncSourceId(e);
  if (!srcId) continue;
  if (revopsSyncedMap.has(srcId)) {
    const prev = revopsSyncedMap.get(srcId);
    const keepNew = new Date(e.updated || e.created || 0) >= new Date(prev.updated || prev.created || 0);
    const toDelete = keepNew ? prev : e;
    if (keepNew) revopsSyncedMap.set(srcId, e);
    actions.push({
      direction: 'to-revops', method: 'DELETE',
      url: 'https://www.googleapis.com/calendar/v3/calendars/' + REVOPS_CAL + '/events/' + toDelete.id + '?sendUpdates=none',
      body: '{}'
    });
  } else {
    revopsSyncedMap.set(srcId, e);
  }
}

for (const event of clientReal) {
  if (!event.start?.dateTime) continue;
  if (event.status === 'cancelled') continue;
  const attendees = getAttendeeEmails(event);
  if (attendees.includes(REVOPS_EMAIL)) { revopsSyncedMap.delete(event.id); continue; }
  const existing = revopsSyncedMap.get(event.id);
  if (existing) {
    if (existing.start?.dateTime !== event.start?.dateTime || existing.end?.dateTime !== event.end?.dateTime ||
        existing.summary !== (PREFIX + ' ' + (event.summary || 'Untitled')) || existing.description !== (event.description || '')) {
      actions.push({
        direction: 'to-revops',
        method: 'PATCH',
        url: 'https://www.googleapis.com/calendar/v3/calendars/' + REVOPS_CAL + '/events/' + existing.id + '?sendUpdates=none',
        body: JSON.stringify({
          summary: PREFIX + ' ' + (event.summary || 'Untitled'),
          description: event.description || '',
          start: { dateTime: event.start.dateTime, timeZone: event.start.timeZone || 'America/New_York' },
          end: { dateTime: event.end.dateTime, timeZone: event.end.timeZone || 'America/New_York' },
          reminders: { useDefault: false, overrides: [] }
        })
      });
    }
    revopsSyncedMap.delete(event.id);
  } else {
    actions.push({
      direction: 'to-revops',
      method: 'POST',
      url: 'https://www.googleapis.com/calendar/v3/calendars/' + REVOPS_CAL + '/events?sendUpdates=none',
      body: JSON.stringify({
        summary: PREFIX + ' ' + (event.summary || 'Untitled'),
        description: event.description || '',
        start: { dateTime: event.start.dateTime, timeZone: event.start.timeZone || 'America/New_York' },
        end: { dateTime: event.end.dateTime, timeZone: event.end.timeZone || 'America/New_York' },
        transparency: 'opaque',
        reminders: { useDefault: false, overrides: [] },
        extendedProperties: { private: { syncSource: SYNC_TAG, syncSourceId: event.id } }
      })
    });
  }
}
for (const [srcId, syncedEvent] of revopsSyncedMap) {
  actions.push({
    direction: 'to-revops',
    method: 'DELETE',
    url: 'https://www.googleapis.com/calendar/v3/calendars/' + REVOPS_CAL + '/events/' + syncedEvent.id + '?sendUpdates=none',
    body: '{}'
  });
}

if (actions.length === 0) {
  return [{ json: { direction: 'none', method: 'NONE', url: '', body: '', stats: 'No sync actions needed' } }];
}

return actions.map(a => ({ json: a }));

// Count results from both branches
const items = $input.all();
const timestamp = new Date().toISOString();
const total = items.length;
const errors = items.filter(i => i.json.error || (i.json.statusCode && i.json.statusCode >= 400)).length;

return [{ json: { status: 'complete', timestamp, totalActions: total, errors } }];
